import { useRef, useEffect } from 'react';

// Хук предназначен для запоминания значения функционального компонента, вычисленного во время предыдущего рендеринга.
const usePrevious = (value) => {
    const ref = useRef(undefined);
    useEffect(() => {
        ref.current = value;
    }, [value]);
    return ref.current;
};

export { usePrevious };
